import React from 'react';
import Particles from 'react-tsparticles';

const ParticleBackground = () => {
  return (
    <Particles
      id="tsparticles"
      options={{
        background: {
          color: {
            value: '#1E1E1E', // Background color of the website
          },
        },
        particles: {
          number: {
            value: 80, // Number of particles
            density: {
              enable: true,
              value_area: 800, // Adjust the density of particles
            },
          },
          color: {
            value: ['#92C9FF', '#72A1E5', '#FFC58F', '#FFAA7B'], // Particle colors (light blue and orange shades)
          },
          shape: {
            type: 'circle', // Particle shape (circle, edge, triangle, polygon, star, image)
          },
          opacity: {
            value: 0.8, // Particle opacity
            random: true, // Randomize particle opacity
            anim: {
              enable: true,
              speed: 0.2,
              opacity_min: 0,
              sync: false,
            },
          },
          size: {
            value: 3, // Particle size
            random: true, // Randomize particle size
            anim: {
              enable: false,
              speed: 4,
              size_min: 0.3,
              sync: false,
            },
          },
          line_linked: {
            enable: true,
            distance: 150, // Distance between connected particles
            color: '#ffffff', // Line color
            opacity: 0.6, // Line opacity
            width: 1, // Line width
          },
          move: {
            enable: true,
            speed: 1, // Particle movement speed
            direction: 'none', // Particle movement direction (none, top, top-right, right, bottom-right, bottom, bottom-left, left, top-left)
            random: true, // Randomize particle movement direction
            straight: false, // Disable straight line movement
            out_mode: 'out', // What to do when a particle moves out of the canvas (out or bounce)
            bounce: false,
            attract: {
              enable: false,
              rotateX: 600,
              rotateY: 1200,
            },
          },
        },
        interactivity: {
          detect_on: 'canvas',
          events: {
            onhover: {
              enable: true,
              mode: 'repulse', // Particle behavior on hover (grab, bubble, repulse, connect)
            },
            onclick: {
              enable: true,
              mode: 'push', // Particle behavior on click (push or remove)
            },
            resize: true,
          },
          modes: {
            grab: {
              distance: 400,
              line_linked: {
                opacity: 1,
              },
            },
            bubble: {
              distance: 250,
              size: 0,
              duration: 2,
              opacity: 0,
              speed: 3,
            },
            repulse: {
              distance: 100, // Distance of repulsion on hover
              duration: 0.4,
            },
            push: {
              particles_nb: 4, // Number of particles to push on click
            },
            remove: {
              particles_nb: 2, // Number of particles to remove on click
            },
          },
        },
        retina_detect: true,
      }}
    />
  );
};

export default ParticleBackground;
